module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
); 
//Enter your code here
reg [2:0] state, next_state;
parameter S0 = 3'b000;
parameter S1 = 3'b001;
parameter S2 = 3'b010;
parameter S3 = 3'b011;
parameter S4 = 3'b100;
parameter S5 = 3'b101;
always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= S0;
    end else begin
        state <= next_state;
    end
end
always @(*) begin
    case (state)
        S0: begin
            if (IN) next_state = S1;
            else next_state = S0;
        end
        S1: begin
            if (IN) next_state = S1;
            else next_state = S2;
        end
        S2: begin
            if (IN) next_state = S1;
            else next_state = S3;
        end
        S3: begin
            if (IN) next_state = S4;
            else next_state = S0;
        end
        S4: begin
            if (IN) next_state = S5;
            else next_state = S0;
        end
        S5: begin
            if (IN) next_state = S1;
            else next_state = S0;
        end
        default: next_state = S0;
    endcase
end
always @(*) begin
    case (state)
        S0: MATCH = 0;
        S1: MATCH = 0;
        S2: MATCH = 0;
        S3: MATCH = 0;
        S4: MATCH = 0;
        S5: MATCH = 1;
        default: MATCH = 0;
    endcase
end
endmodule
